  1→import { lazy, Suspense } from 'react'
  2→import './App.css'
  3→import { Routes, Route, BrowserRouter, Navigate} from 'react-router-dom'
  4→import { useAuth } from './Context/useAuth.js';
  5→import { LexicalComposer } from '@lexical/react/LexicalComposer';
  6→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  7→import ImageNode from './components/HomePage/Editor/nodes/ImageNode.jsx';
  8→import Loader from './components/loadingComponent/BgLoader.jsx';
  9→import SeoManager from './seo/SeoManager.jsx';
 10→
 11→const AuthModal = lazy(() => import('./components/AuthModal/AuthModal.jsx'));
 12→const HomePage = lazy(() => import('./components/HomePage/Home.jsx'));
 13→const LoginPage = lazy(() => import('./components/LoginPage/login.jsx'));
 14→const SignUp = lazy(() => import('./components/SignUpPage/signup.jsx'));
 15→const MyProfile = lazy(() => import('./components/ProfilePage/MyProfile.jsx'));
 16→const PostCards = lazy(() => import('./components/HomePage/postCards/PostCards.jsx'));
 17→const ContentView = lazy(() => import('./components/HomePage/ContentViewer/ContentView.jsx'));
 18→const Bookmarks = lazy(() => import('./components/Bookmarks/Bookmarks.jsx'));
 19→const Visitprofile = lazy(() => import('./components/VisitProfile/VisitProfile.jsx'));
 20→const ProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/ProfilePostCards.jsx'));
 21→const ProfileMediaSection = lazy(() => import('./components/ProfilePage/components/ProfileMediaSection.jsx'));
 22→const VisitedProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/VisitedProfilePostCards.jsx'));
 23→const VisitedProfileMediaSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileMediaSection.jsx'));
 24→const Notifications = lazy(() => import('./components/Notifications/Notifications.jsx'));
 25→const NotificationCards = lazy(() => import('./components/Notifications/notificationsCards.jsx'));
 26→const UnreadNotification = lazy(() => import('./components/Notifications/UnreadNotificationCard.jsx'));
 27→const Collections = lazy(() => import('./components/collections/Collection.jsx'));
 28→const CollectionJournals = lazy(() => import('./components/collections/CollectionJournalCards.jsx'));
 29→const CollectionViewer = lazy(() => import('./components/collections/CollectionViewer.jsx'));
 30→const ViewUserCollection = lazy(() => import('./components/collections/ViewUserCollections.jsx'));
 31→const OpinionsPage = lazy(() => import('./components/SidebarOpinions/OpinionssPage.jsx'));
 32→const VisitedProfileOpinions = lazy(() => import('./components/SidebarOpinions/visitedProfileOpinions.jsx'));
 33→const MyOpinions = lazy(() => import('./components/SidebarOpinions/MyOpinions.jsx'));
 34→const OpinionViewer = lazy(() => import('./components/SidebarOpinions/opinionViewer.jsx'));
 35→const ExplorePage = lazy(() => import('./components/HomePage/explore/ExplorePage.jsx'));
 36→const GalleryPage = lazy(() => import('./components/HomePage/gallery/GalleryPage.jsx'));
 37→const FreedomWallPage = lazy(() => import('./components/HomePage/freedomWall/FreedomWallPage.jsx'));
 38→const Universe = lazy(() => import('./components/Universe/Universe.jsx'));
 39→const SettingsPage = lazy(() => import('./components/SettingsPage/SettingsPage.jsx'));
 40→const StoryDashboard = lazy(() => import('./components/Stories/StoryDashboard/StoryDashboard.jsx'));
 41→const StoryEditor = lazy(() => import('./components/Stories/StoryEditor/StoryEditor.jsx'));
 42→const StoryChapterManager = lazy(() => import('./components/Stories/StoryChapterManager/StoryChapterManager.jsx'));
 43→const ChapterEditor = lazy(() => import('./components/Stories/ChapterEditor/ChapterEditor.jsx'));
 44→const StoryBrowser = lazy(() => import('./components/Stories/StoryBrowser/StoryBrowser.jsx'));
 45→const StoryDetail = lazy(() => import('./components/Stories/StoryDetail/StoryDetail.jsx'));
 46→const ChapterReader = lazy(() => import('./components/Stories/ChapterReader/ChapterReader.jsx'));
 47→
 48→const AppAuthModal = () => {
 49→  const {showAuthModal, closeAuthModal} = useAuth();
 50→  return <AuthModal isOpen={showAuthModal} onClose={closeAuthModal}/>;
 51→}
 52→
 53→const AppSplash = () => {
 54→  const { loading } = useAuth();
 55→  return <Loader isLoading={loading} />;
 56→}
 57→
 58→const App = () => {
 59→
 60→  const theme = {
 61→    paragraph: 'editor-paragraph',
 62→    heading: {
 63→      h1: 'editor-heading-h1',
 64→      h2: 'editor-heading-h2',
 65→      h3: 'editor-heading-h3',
 66→    },
 67→    quote: 'editor-quote',
 68→    text: {
 69→      bold: 'editor-text-bold',
 70→      italic: 'editor-text-italic',
 71→      underline: 'editor-text-underline',
 72→    }
 73→  }
 74→  
 75→  const initaConfig = {
 76→  namespace: "MyLexicalEditor",
 77→  theme,
 78→  //register nodes
 79→  nodes: [ImageNode, HeadingNode, QuoteNode],
 80→  onError(error){
 81→  throw error;
 82→  },
 83→}
 84→
 85→  return (
 86→    <>
 87→    <LexicalComposer initialConfig={initaConfig}>
 88→      <BrowserRouter>
 89→        <SeoManager />
 90→        <AppSplash />
 91→        <Suspense fallback={null}>
 92→          <AppAuthModal/>
 93→          <Routes>
 94→            <Route path='/' element={<Navigate to='/home' replace/>}/>
 95→            <Route path='/index.html' element={<Navigate to='/home' replace/>}/>
 96→            <Route path='/profile' element={<MyProfile/>}>
 97→              <Route index element={<ProfilePostCards/>} />
 98→              <Route path='media' element={<ProfileMediaSection/>} />
 99→              <Route path='myOpinions' element={<MyOpinions/>}/>         
100→            </Route>
101→
102→            <Route path='/visitProfile' element={<Visitprofile/>}>
103→              <Route index element={<VisitedProfilePostCards/>}/>
104→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
105→              <Route path='visitedCollections' element={<CollectionViewer/>}/>
106→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
107→            </Route>
108→
109→            <Route path='/u/:username' element={<Visitprofile/>}>
110→              <Route index element={<VisitedProfilePostCards/>}/>
111→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
112→              <Route path='collections' element={<CollectionViewer/>}/>
113→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
114→            </Route>
115→
116→            <Route path='/home' element={<HomePage/>}>
117→              <Route index element={<PostCards/>}/>
118→              <Route path='explore' element={<ExplorePage/>}/>
119→              <Route path='gallery' element={<GalleryPage/>}/>
120→              <Route path='freedom-wall' element={<FreedomWallPage/>}/>
121→              <Route path='contentViewer' element={<ContentView/>}/>
122→              <Route path='post/:journalId' element={<ContentView/>}/>
123→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
124→              <Route path='bookmark' element={<Bookmarks/>}/>
125→              <Route path='userCollections' element={<ViewUserCollection/>}/>
126→              <Route path='opinions'element={<OpinionsPage/>}/>
127→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
128→
129→              <Route path='collections' element={<Collections/>}/>
130→              <Route path='collectionCards' element={<CollectionJournals/>}/>
131→              <Route path='settings' element={<SettingsPage/>}/>
132→
133→              {/* Stories routes */}
134→              <Route path='stories' element={<StoryBrowser/>}/>
135→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
136→              <Route path='stories/new' element={<StoryEditor/>}/>
137→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
138→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
139→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
140→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
141→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
142→
143→              {/* route for nested notifications */}
144→              <Route path='notifications' element={<Notifications/>}>
145→                <Route index element={<NotificationCards/>}/>
146→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
147→              </Route>  
148→            </Route>   
149→
150→            <Route path='/universe' element={<Universe/>}/>
151→
152→            <Route path='/login' element={<LoginPage/>}/>
153→            <Route path='/signUp' element={<SignUp/>}/>
154→          </Routes>
155→        </Suspense>
156→      </BrowserRouter>
157→    </LexicalComposer>
158→    </>
159→  )
160→}
161→
162→export default App
163→

  1→import React, { useState } from 'react';
  2→import { useNavigate } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useInfiniteQuery } from '@tanstack/react-query';
  5→import { getStories } from '../../../../API/StoryApi';
  6→import { motion } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import './StoryBrowser.css';
  9→
 10→const STATUS_LABELS = { ongoing: 'Ongoing', completed: 'Completed', hiatus: 'Hiatus' };
 11→const STATUS_FILTERS = [
 12→    { value: null, label: 'All' },
 13→    { value: 'ongoing', label: 'Ongoing' },
 14→    { value: 'completed', label: 'Completed' },
 15→    { value: 'hiatus', label: 'Hiatus' },
 16→];
 17→
 18→const StoryCard = ({ story, onClick }) => {
 19→    const author = story.users;
 20→    return (
 21→        <motion.div
 22→            className="story-card"
 23→            initial={{ opacity: 0, y: 10 }}
 24→            animate={{ opacity: 1, y: 0 }}
 25→            whileHover={{ y: -3 }}
 26→            onClick={onClick}
 27→        >
 28→            <div className="story-card-cover">
 29→                {story.cover_url ? (
 30→                    <img src={story.cover_url} alt={story.title} loading="lazy" />
 31→                ) : (
 32→                    <div className="story-card-cover-placeholder">
 33→                        <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="var(--text-muted)">
 34→                            <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
 35→                        </svg>
 36→                    </div>
 37→                )}
 38→            </div>
 39→            <div className="story-card-info">
 40→                <h3 className="story-card-title">{story.title}</h3>
 41→                {author && (
 42→                    <div className="story-card-author">
 43→                        {author.image_url && <img src={author.image_url} alt="" className="story-card-author-avatar" />}
 44→                        <span>{author.name}</span>
 45→                    </div>
 46→                )}
 47→                <div className="story-card-meta">
 48→                    <span className={`story-status-badge story-status-${story.status}`}>
 49→                        {STATUS_LABELS[story.status] || story.status}
 50→                    </span>
 51→                    <span className="story-card-stats">
 52→                        {(story.vote_count || 0)} votes &middot; {(story.read_count || 0)} reads
 53→                    </span>
 54→                </div>
 55→                {story.tags && story.tags.length > 0 && (
 56→                    <div className="story-card-tags">
 57→                        {story.tags.slice(0, 3).map(tag => (
 58→                            <span key={tag} className="story-card-tag">{tag}</span>
 59→                        ))}
 60→                    </div>
 61→                )}
 62→            </div>
 63→        </motion.div>
 64→    );
 65→};
 66→
 67→const StoryBrowser = () => {
 68→    const navigate = useNavigate();
 69→    const { session } = useAuth();
 70→    const token = session?.access_token;
 71→    const [statusFilter, setStatusFilter] = useState(null);
 72→
 73→    const {
 74→        data,
 75→        isLoading,
 76→        hasNextPage,
 77→        fetchNextPage,
 78→        isFetchingNextPage,
 79→    } = useInfiniteQuery({
 80→        queryKey: ['storiesBrowse', statusFilter],
 81→        queryFn: ({ pageParam = null }) => getStories(12, pageParam, statusFilter, null, token),
 82→        getNextPageParam: (lastPage) => {
 83→            if (!lastPage?.hasMore || !lastPage.data?.length) return undefined;
 84→            return lastPage.data[lastPage.data.length - 1].created_at;
 85→        },
 86→        initialPageParam: null,
 87→        refetchOnWindowFocus: false,
 88→    });
 89→
 90→    const stories = data?.pages?.flatMap(p => p.data) || [];
 91→
 92→    return (
 93→        <div className="story-browser">
 94→            <div className="story-browser-header">
 95→                <h2 className="story-browser-title">Stories</h2>
 96→                {session && (
 97→                    <div className="story-browser-header-actions">
 98→                        <button
 99→                            className="story-browser-my-btn"
100→                            onClick={() => navigate('/home/stories/dashboard')}
101→                        >
102→                            My Stories
103→                        </button>
104→                        <button
105→                            className="story-browser-new-btn"
106→                            onClick={() => navigate('/home/stories/new')}
107→                        >
108→                            + Write
109→                        </button>
110→                    </div>
111→                )}
112→            </div>
113→
114→            <div className="story-browser-filters">
115→                {STATUS_FILTERS.map(f => (
116→                    <button
117→                        key={f.label}
118→                        className={`story-filter-btn ${statusFilter === f.value ? 'story-filter-btn-active' : ''}`}
119→                        onClick={() => setStatusFilter(f.value)}
120→                    >
121→                        {f.label}
122→                    </button>
123→                ))}
124→            </div>
125→
126→            {isLoading ? (
127→                <div className="story-browser-loading">
128→                    <BeatLoader size={10} color="var(--text-muted)" />
129→                </div>
130→            ) : stories.length === 0 ? (
131→                <div className="story-browser-empty">
132→                    <p>No stories found.</p>
133→                </div>
134→            ) : (
135→                <>
136→                    <div className="story-browser-grid">
137→                        {stories.map(story => (
138→                            <StoryCard
139→                                key={story.id}
140→                                story={story}
141→                                onClick={() => navigate(`/home/stories/${story.id}`)}
142→                            />
143→                        ))}
144→                    </div>
145→                    {hasNextPage && (
146→                        <div className="story-browser-load-more">
147→                            <button
148→                                className="story-browser-load-more-btn"
149→                                onClick={() => fetchNextPage()}
150→                                disabled={isFetchingNextPage}
151→                            >
152→                                {isFetchingNextPage ? (
153→                                    <BeatLoader size={8} color="var(--text-secondary)" />
154→                                ) : (
155→                                    'Load more'
156→                                )}
157→                            </button>
158→                        </div>
159→                    )}
160→                </>
161→            )}
162→        </div>
163→    );
164→};
165→
166→export default StoryBrowser;
