  1→import React from 'react';
  2→import { useNavigate, useParams } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useStoryDetail } from '../hooks/useStoryData';
  5→import { useToggleVote, useToggleLibrary } from '../hooks/useStoryMutations';
  6→import { motion } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import './StoryDetail.css';
  9→
 10→const STATUS_LABELS = { ongoing: 'Ongoing', completed: 'Completed', hiatus: 'Hiatus' };
 11→
 12→const StoryDetail = () => {
 13→    const { storyId } = useParams();
 14→    const navigate = useNavigate();
 15→    const { session, openAuthModal } = useAuth();
 16→    const token = session?.access_token;
 17→
 18→    const { data: story, isLoading } = useStoryDetail(storyId, token);
 19→    const voteMutation = useToggleVote(token);
 20→    const libraryMutation = useToggleLibrary(token);
 21→
 22→    const handleVote = () => {
 23→        if (!session) return openAuthModal();
 24→        voteMutation.mutate(storyId);
 25→    };
 26→
 27→    const handleLibrary = () => {
 28→        if (!session) return openAuthModal();
 29→        libraryMutation.mutate(storyId);
 30→    };
 31→
 32→    const handleStartReading = () => {
 33→        // If there's reading progress, resume from there
 34→        if (story?.reading_progress?.chapter_id) {
 35→            navigate(`/home/stories/${storyId}/chapter/${story.reading_progress.chapter_id}`);
 36→            return;
 37→        }
 38→        // Otherwise start from first published chapter
 39→        const firstChapter = story?.chapters?.[0];
 40→        if (firstChapter) {
 41→            navigate(`/home/stories/${storyId}/chapter/${firstChapter.id}`);
 42→        }
 43→    };
 44→
 45→    if (isLoading) {
 46→        return (
 47→            <div className="story-detail">
 48→                <div className="story-detail-loading">
 49→                    <BeatLoader size={10} color="var(--text-muted)" />
 50→                </div>
 51→            </div>
 52→        );
 53→    }
 54→
 55→    if (!story) {
 56→        return (
 57→            <div className="story-detail">
 58→                <p className="story-detail-error">Story not found.</p>
 59→            </div>
 60→        );
 61→    }
 62→
 63→    const author = story.users;
 64→    const chapters = story.chapters || [];
 65→    const hasProgress = !!story.reading_progress;
 66→    const totalWords = chapters.reduce((sum, ch) => sum + (ch.word_count || 0), 0);
 67→
 68→    return (
 69→        <motion.div
 70→            className="story-detail"
 71→            initial={{ opacity: 0 }}
 72→            animate={{ opacity: 1 }}
 73→            transition={{ duration: 0.2 }}
 74→        >
 75→            {/* Hero section */}
 76→            <div className="story-detail-hero">
 77→                <div className="story-detail-cover">
 78→                    {story.cover_url ? (
 79→                        <img src={story.cover_url} alt={story.title} />
 80→                    ) : (
 81→                        <div className="story-detail-cover-placeholder">
 82→                            <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="var(--text-muted)">
 83→                                <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
 84→                            </svg>
 85→                        </div>
 86→                    )}
 87→                </div>
 88→                <div className="story-detail-hero-info">
 89→                    <h1 className="story-detail-title">{story.title}</h1>
 90→                    {author && (
 91→                        <div
 92→                            className="story-detail-author"
 93→                            onClick={() => author.username ? navigate(`/u/${author.username}`) : null}
 94→                        >
 95→                            {author.image_url && (
 96→                                <img src={author.image_url} alt="" className="story-detail-author-avatar" />
 97→                            )}
 98→                            <span className="story-detail-author-name">{author.name}</span>
 99→                        </div>
100→                    )}
101→                    <div className="story-detail-stats">
102→                        <span className={`story-status-badge story-status-${story.status}`}>
103→                            {STATUS_LABELS[story.status] || story.status}
104→                        </span>
105→                        <span>{chapters.length} chapter{chapters.length !== 1 ? 's' : ''}</span>
106→                        <span>{totalWords.toLocaleString()} words</span>
107→                        <span>{(story.read_count || 0).toLocaleString()} reads</span>
108→                        <span>{(story.vote_count || 0).toLocaleString()} votes</span>
109→                    </div>
110→                    {story.tags && story.tags.length > 0 && (
111→                        <div className="story-detail-tags">
112→                            {story.tags.map(tag => (
113→                                <span key={tag} className="story-detail-tag">{tag}</span>
114→                            ))}
115→                        </div>
116→                    )}
117→                </div>
118→            </div>
119→
120→            {/* Action buttons */}
121→            <div className="story-detail-actions">
122→                {chapters.length > 0 && (
123→                    <button className="story-detail-read-btn" onClick={handleStartReading}>
124→                        {hasProgress ? 'Continue Reading' : 'Start Reading'}
125→                    </button>
126→                )}
127→                <button
128→                    className={`story-detail-vote-btn ${story.has_voted ? 'story-detail-vote-btn-active' : ''}`}
129→                    onClick={handleVote}
130→                >
131→                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill={story.has_voted ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
132→                        <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
133→                    </svg>
134→                    {story.vote_count || 0}
135→                </button>
136→                <button
137→                    className={`story-detail-library-btn ${story.in_library ? 'story-detail-library-btn-active' : ''}`}
138→                    onClick={handleLibrary}
139→                >
140→                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill={story.in_library ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
141→                        <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"/>
142→                    </svg>
143→                    {story.in_library ? 'In Library' : 'Add to Library'}
144→                </button>
145→            </div>
146→
147→            {/* Description */}
148→            {story.description && (
149→                <div className="story-detail-description">
150→                    <h3>About</h3>
151→                    <p>{story.description}</p>
152→                </div>
153→            )}
154→
155→            {/* Chapter list */}
156→            <div className="story-detail-chapters">
157→                <h3>Chapters ({chapters.length})</h3>
158→                {chapters.length === 0 ? (
159→                    <p className="story-detail-no-chapters">No chapters published yet.</p>
160→                ) : (
161→                    <div className="story-detail-chapter-list">
162→                        {chapters.map((ch) => (
163→                            <div
164→                                key={ch.id}
165→                                className="story-detail-chapter-item"
166→                                onClick={() => navigate(`/home/stories/${storyId}/chapter/${ch.id}`)}
167→                            >
168→                                <div className="story-detail-chapter-left">
169→                                    <span className="story-detail-chapter-number">Ch. {ch.chapter_number}</span>
170→                                    <span className="story-detail-chapter-title">{ch.title}</span>
171→                                </div>
172→                                <div className="story-detail-chapter-right">
173→                                    <span className="story-detail-chapter-words">{(ch.word_count || 0).toLocaleString()} words</span>
174→                                </div>
175→                            </div>
176→                        ))}
